#!/usr/bin/env python3
"""
Bug #2563: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['layout', 'resize_cubic_halfpixel'], ['layout', 'reshape_rank2_roundtrip'], ['constant', 'redundant_reshape'], ['broadcast', 'log_abs_eps'], ['constant', 'cast_int_roundtrip'], ['normalization', 'variance_whitening']]
Dependencies: numpy jax
Run         : python unique_2563.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w1 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w2 = np.frombuffer(bytes.fromhex("03000000000000000010000000000000"), dtype=np.int64).reshape([2])
_w3 = np.frombuffer(bytes.fromhex("0100000000000000030000000000000040000000000000004000000000000000"), dtype=np.int64).reshape([4])
_w4 = np.frombuffer(bytes.fromhex("ffffffffffffffff0030000000000000"), dtype=np.int64).reshape([2])
_w5 = np.frombuffer(bytes.fromhex("ffffffffffffffff030000000000000040000000000000004000000000000000"), dtype=np.int64).reshape([4])
_w6 = np.frombuffer(bytes.fromhex("17b7d138"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex("0000c8c2"), dtype=np.float32).reshape([1])
_w8 = np.frombuffer(bytes.fromhex("0000c842"), dtype=np.float32).reshape([1])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 64, 64])
_w10 = np.frombuffer(bytes.fromhex("acc52737"), dtype=np.float32).reshape([1])
_w11 = np.frombuffer(bytes.fromhex("0000003f"), dtype=np.float32).reshape([1])
_w12 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1, 1, 1, 1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(x, _w1)
    n100_r2r_r1 = jnp.reshape(n0_resi_out, [int(v) for v in _w2.flat])
    n100_r2r_out = jnp.reshape(n100_r2r_r1, [int(v) for v in _w3.flat])
    n200_rrsh_r1 = jnp.reshape(n100_r2r_out, [int(v) for v in _w4.flat])
    n200_rrsh_out = jnp.reshape(n200_rrsh_r1, [int(v) for v in _w5.flat])
    n300_lgs_ab = jnp.abs(n200_rrsh_out)
    n300_lgs_ad = n300_lgs_ab + _w6
    n300_lgs_lg = jnp.log(n300_lgs_ad)
    n300_lgs_out = n300_lgs_lg * n200_rrsh_out
    n400_cirt_cl = jnp.minimum(jnp.maximum(n300_lgs_out, jnp.asarray(_w7, dtype=n300_lgs_out.dtype)), jnp.asarray(_w8, dtype=jnp.maximum(n300_lgs_out, jnp.asarray(_w7, dtype=n300_lgs_out.dtype)).dtype))
    n400_cirt_i32 = n400_cirt_cl.astype(np.int32)
    n400_cirt_f32 = n400_cirt_i32.astype(np.float32)
    n400_cirt_out = n400_cirt_f32 * _w9
    n500_vw_mean = jnp.mean(n400_cirt_out, axis=(-1,), keepdims=True)
    n500_vw_diff = n400_cirt_out - n500_vw_mean
    n500_vw_sq = n500_vw_diff * n500_vw_diff
    n500_vw_var = jnp.mean(n500_vw_sq, axis=(-1,), keepdims=True)
    n500_vw_add = n500_vw_var + _w10
    n500_vw_std = n500_vw_add ** np.float32(_w11.flat[0])
    n500_vw_div = n500_vw_diff / n500_vw_std
    n500_vw_out = n500_vw_div * _w12
    return jnp.asarray(n500_vw_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
